const ticket = $input.first().json.ticket || $input.first().json.body?.ticket;
const num = ticket.replace(/\D/g,'');
return [{
  json: {
    ticket: ticket.toUpperCase(),
    num,
    sshp: `SSHP-${num}`,
    jira_url: `https://mercadolibre.atlassian.net/rest/api/3/issue/SSHP-${num}`,
    confluence_url: `https://mercadolibre.atlassian.net/wiki/rest/api/content/search?cql=space=%22ISSM%22%20AND%20text~%22${num}%22`,
    datadog_url: `https://api.datadoghq.com/api/v2/incidents?filter[query]=${num}`,
    slack_query: `SSHP-${num}`
  }
}];

const data = $input.first().json;
const ticket = data.ticket;
const report = data.report || '';

// Extrai resumo executivo
const execMatch = report.match(/## 📊 RESUMO EXECUTIVO[\s\S]*?(?=## |$)/);
const execSummary = execMatch ? execMatch[0].replace(/## 📊 RESUMO EXECUTIVO/,'').trim().slice(0,800) : 'Análise completa disponível no grid.';

// Extrai action items
const actionMatch = report.match(/## ✅ ACTION ITEMS[\s\S]*?(?=## |$)/);
const actionItems = actionMatch ? actionMatch[0].replace(/## ✅ ACTION ITEMS PRIORIZADOS/,'').trim().slice(0,400) : '';

return [{
  json: {
    ticket,
    exec_summary: execSummary,
    action_items: actionItems,
    grid_url: data.grid_url || '',
    drive_url: data.drive_url || '',
    duration: data.duration_seconds,
    sources: data.sources_consulted?.filter(s => s.startsWith('✅')).length || 0
  }
}];

